/**
 * Generated by `createservice subscription.UpdateSubscriptionContextPaymentMethodService --type mutations`
 */
const { faker } = require('@faker-js/faker')
const dayjs = require('dayjs')

const { getById } = require('@open-condo/keystone/schema')
const { makeLoggedInAdminClient, makeClient, makeClientWithSupportUser, makeClientWithNewRegisteredAndLoggedInUser, expectToThrowGQLError } = require('@open-condo/keystone/test.utils')
const { expectToThrowAccessDeniedErrorToResult, expectToThrowAuthenticationErrorToResult } = require('@open-condo/keystone/test.utils')

const { CONTEXT_FINISHED_STATUS } = require('@condo/domains/acquiring/constants/context')
const {
    createTestAcquiringIntegration,
    createTestAcquiringIntegrationContext,
} = require('@condo/domains/acquiring/utils/testSchema')
const { createTestRecipient } = require('@condo/domains/billing/utils/testSchema')
const { MANAGING_COMPANY_TYPE } = require('@condo/domains/organization/constants/common')
const { createTestOrganizationEmployeeRole, createTestOrganizationEmployee } = require('@condo/domains/organization/utils/testSchema')
const { registerNewOrganization } = require('@condo/domains/organization/utils/testSchema')
const { SUBSCRIPTION_CONTEXT_STATUS } = require('@condo/domains/subscription/constants')
const { ERRORS } = require('@condo/domains/subscription/schema/UpdateSubscriptionContextPaymentMethodService')
const {
    createTestSubscriptionContext,
    createTestSubscriptionPlan,
    updateSubscriptionContextPaymentMethodByTestClient,
} = require('@condo/domains/subscription/utils/testSchema')

describe('UpdateSubscriptionContextPaymentMethodService', () => {
    let admin, support, anonymous, user
    let subscriptionPlan, organization
    let recipientOrganization, acquiringIntegration
    let originalSubscriptionPaymentRecipient

    beforeAll(async () => {
        admin = await makeLoggedInAdminClient()
        support = await makeClientWithSupportUser()
        anonymous = await makeClient()

        const [recipientOrg] = await registerNewOrganization(admin, { type: MANAGING_COMPANY_TYPE })
        recipientOrganization = recipientOrg

        originalSubscriptionPaymentRecipient = process.env.SUBSCRIPTION_PAYMENT_RECIPIENT
        process.env.SUBSCRIPTION_PAYMENT_RECIPIENT = recipientOrganization.id

        const [integration] = await createTestAcquiringIntegration(admin)
        acquiringIntegration = integration
        await createTestAcquiringIntegrationContext(admin, recipientOrganization, acquiringIntegration, {
            invoiceStatus: CONTEXT_FINISHED_STATUS,
            invoiceRecipient: createTestRecipient(),
            invoiceImplicitFeeDistributionSchema: [],
        })

        const [plan] = await createTestSubscriptionPlan(admin, {
            name: faker.commerce.productName(),
            organizationType: MANAGING_COMPANY_TYPE,
            isHidden: false,
            trialDays: 14,
        })
        subscriptionPlan = plan
    })

    afterAll(() => {
        if (originalSubscriptionPaymentRecipient !== undefined) {
            process.env.SUBSCRIPTION_PAYMENT_RECIPIENT = originalSubscriptionPaymentRecipient
        } else {
            delete process.env.SUBSCRIPTION_PAYMENT_RECIPIENT
        }
    })

    beforeEach(async () => {
        user = await makeClientWithNewRegisteredAndLoggedInUser()
        const [org] = await registerNewOrganization(user, { type: MANAGING_COMPANY_TYPE })
        organization = org
    })

    describe('Access', () => {
        test('admin can update subscription context payment method', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
            })

            const bindingId = faker.datatype.uuid()

            const [result] = await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                subscriptionContext: { id: context.id },
                bindingId,
            })

            expect(result.id).toBe(context.id)

            const updatedContext = await getById('SubscriptionContext', context.id)
            expect(updatedContext.bindingId).toBe(bindingId)
        })

        test('support can update subscription context payment method', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
            })

            const bindingId = faker.datatype.uuid()

            const [result] = await updateSubscriptionContextPaymentMethodByTestClient(support, {
                subscriptionContext: { id: context.id },
                bindingId,
            })

            expect(result.id).toBe(context.id)
        })

        test('employee with canManageSubscriptions can update payment method', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
            })

            const [role] = await createTestOrganizationEmployeeRole(admin, organization, {
                canManageSubscriptions: true,
            })

            const employeeUser = await makeClientWithNewRegisteredAndLoggedInUser()
            await createTestOrganizationEmployee(admin, organization, employeeUser.user, role)

            const bindingId = faker.datatype.uuid()

            const [result] = await updateSubscriptionContextPaymentMethodByTestClient(employeeUser, {
                subscriptionContext: { id: context.id },
                bindingId,
            })

            expect(result.id).toBe(context.id)
        })

        test('employee without canManageSubscriptions cannot update payment method', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
            })

            const [role] = await createTestOrganizationEmployeeRole(admin, organization, {
                canManageSubscriptions: false,
            })

            const employeeUser = await makeClientWithNewRegisteredAndLoggedInUser()
            await createTestOrganizationEmployee(admin, organization, employeeUser.user, role)

            const bindingId = faker.datatype.uuid()

            await expectToThrowAccessDeniedErrorToResult(async () => {
                await updateSubscriptionContextPaymentMethodByTestClient(employeeUser, {
                    subscriptionContext: { id: context.id },
                    bindingId,
                })
            })
        })

        test('regular user without employment cannot update payment method', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
            })

            const regularUser = await makeClientWithNewRegisteredAndLoggedInUser()
            const bindingId = faker.datatype.uuid()

            await expectToThrowAccessDeniedErrorToResult(async () => {
                await updateSubscriptionContextPaymentMethodByTestClient(regularUser, {
                    subscriptionContext: { id: context.id },
                    bindingId,
                })
            })
        })

        test('anonymous cannot update payment method', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
            })

            await expectToThrowAuthenticationErrorToResult(async () => {
                await updateSubscriptionContextPaymentMethodByTestClient(anonymous, {
                    subscriptionContext: { id: context.id },
                    bindingId: null,
                })
            })
        })
    })

    describe('Validation', () => {
        test('throws error if subscription context not found', async () => {
            const fakeId = faker.datatype.uuid()

            await expectToThrowGQLError(async () => {
                await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                    subscriptionContext: { id: fakeId },
                    bindingId: null,
                })
            }, ERRORS.SUBSCRIPTION_CONTEXT_NOT_FOUND, 'result')
        })

        test('throws error if subscription context is deleted', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                deletedAt: dayjs().toISOString(),
            })

            await expectToThrowGQLError(async () => {
                await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                    subscriptionContext: { id: context.id },
                    bindingId: null,
                })
            }, ERRORS.SUBSCRIPTION_CONTEXT_NOT_FOUND, 'result')
        })
    })

    describe('Payment Method Update Logic', () => {
        test('updates payment method to new value', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId: null,
            })

            const bindingId = faker.datatype.uuid()

            const [result] = await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                subscriptionContext: { id: context.id },
                bindingId,
            })

            expect(result.id).toBe(context.id)

            const updatedContext = await getById('SubscriptionContext', context.id)
            expect(updatedContext.bindingId).toBe(bindingId)
        })

        test('updates payment method from one card to another', async () => {
            const oldPaymentMethodId = faker.datatype.uuid()

            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId: oldPaymentMethodId,
            })

            const newPaymentMethodId = faker.datatype.uuid()

            const [result] = await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                subscriptionContext: { id: context.id },
                bindingId: newPaymentMethodId,
            })

            expect(result.id).toBe(context.id)

            const updatedContext = await getById('SubscriptionContext', context.id)
            expect(updatedContext.bindingId).toBe(newPaymentMethodId)
            expect(updatedContext.bindingId).not.toBe(oldPaymentMethodId)
        })

        test('removes payment method when bindingId is null', async () => {
            const existingPaymentMethodId = faker.datatype.uuid()

            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId: existingPaymentMethodId,
            })

            global.fetch = jest.fn(() => Promise.resolve({ ok: true, json: () => Promise.resolve({}) }))

            const [result] = await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                subscriptionContext: { id: context.id },
                bindingId: null,
            })

            expect(result.id).toBe(context.id)

            const updatedContext = await getById('SubscriptionContext', context.id)
            expect(updatedContext.bindingId).toBeNull()

            const expectedDeleteUrl = `${acquiringIntegration.hostUrl}/api/clients/${organization.id}/card-tokens/${existingPaymentMethodId}`
            expect(global.fetch).toHaveBeenCalledWith(expectedDeleteUrl, { method: 'DELETE' })

            global.fetch.mockRestore()
        })

        test('removes payment method when context has no existing payment method', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId: null,
            })

            global.fetch = jest.fn(() => Promise.resolve({ ok: true, json: () => Promise.resolve({}) }))

            const [result] = await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                subscriptionContext: { id: context.id },
                bindingId: null,
            })

            expect(result.id).toBe(context.id)

            const updatedContext = await getById('SubscriptionContext', context.id)
            expect(updatedContext.bindingId).toBeNull()

            expect(global.fetch).not.toHaveBeenCalled()

            global.fetch.mockRestore()
        })

        test('does not delete card token when other active contexts use the same bindingId', async () => {
            const sharedPaymentMethodId = faker.datatype.uuid()

            const [context1] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId: sharedPaymentMethodId,
            })

            await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().add(1, 'month').add(1, 'day').format('YYYY-MM-DD'),
                endAt: dayjs().add(2, 'months').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId: sharedPaymentMethodId,
            })

            global.fetch = jest.fn(() => Promise.resolve({ ok: true, json: () => Promise.resolve({}) }))

            const [result] = await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                subscriptionContext: { id: context1.id },
                bindingId: null,
            })

            expect(result.id).toBe(context1.id)

            const updatedContext = await getById('SubscriptionContext', context1.id)
            expect(updatedContext.bindingId).toBeNull()

            expect(global.fetch).not.toHaveBeenCalled()

            global.fetch.mockRestore()
        })

        test('deletes card token when other contexts with same bindingId are expired', async () => {
            const sharedPaymentMethodId = faker.datatype.uuid()

            const [context1] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId: sharedPaymentMethodId,
            })

            await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().subtract(2, 'months').format('YYYY-MM-DD'),
                endAt: dayjs().subtract(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId: sharedPaymentMethodId,
            })

            global.fetch = jest.fn(() => Promise.resolve({ ok: true, json: () => Promise.resolve({}) }))

            await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                subscriptionContext: { id: context1.id },
                bindingId: null,
            })

            const expectedDeleteUrl = `${acquiringIntegration.hostUrl}/api/clients/${organization.id}/card-tokens/${sharedPaymentMethodId}`
            expect(global.fetch).toHaveBeenCalledWith(expectedDeleteUrl, { method: 'DELETE' })

            global.fetch.mockRestore()
        })
    })

    describe('Card Token Deletion', () => {
        test('deletes card token from acquiring integration when removing payment method', async () => {
            const bindingId = faker.datatype.uuid()

            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId,
            })

            global.fetch = jest.fn(() => Promise.resolve({ ok: true, json: () => Promise.resolve({}) }))

            await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                subscriptionContext: { id: context.id },
                bindingId: null,
            })

            const expectedDeleteUrl = `${acquiringIntegration.hostUrl}/api/clients/${organization.id}/card-tokens/${bindingId}`
            expect(global.fetch).toHaveBeenCalledWith(expectedDeleteUrl, { method: 'DELETE' })

            global.fetch.mockRestore()
        })

        test('throws error when card token deletion fails', async () => {
            const bindingId = faker.datatype.uuid()

            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId,
            })

            global.fetch = jest.fn(() => Promise.resolve({
                ok: false,
                status: 404,
                json: () => Promise.resolve({ message: 'Card token not found' }),
            }))

            await expectToThrowGQLError(async () => {
                await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                    subscriptionContext: { id: context.id },
                    bindingId: null,
                })
            }, ERRORS.CARD_TOKEN_DELETION_FAILED, 'result')

            global.fetch.mockRestore()
        })

        test('throws error when SUBSCRIPTION_PAYMENT_RECIPIENT is not configured', async () => {
            const bindingId = faker.datatype.uuid()

            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
                bindingId,
            })

            const originalEnv = process.env.SUBSCRIPTION_PAYMENT_RECIPIENT
            delete process.env.SUBSCRIPTION_PAYMENT_RECIPIENT

            await expectToThrowGQLError(async () => {
                await updateSubscriptionContextPaymentMethodByTestClient(admin, {
                    subscriptionContext: { id: context.id },
                    bindingId: null,
                })
            }, ERRORS.SUBSCRIPTION_PAYMENT_RECIPIENT_NOT_CONFIGURED, 'result')

            process.env.SUBSCRIPTION_PAYMENT_RECIPIENT = originalEnv
        })
    })
})